logistic <- function(x){
  1 / (1 + exp(-x))
}

computeU <- function(X_ord, beta_ord, E){
  X_ord %*% beta_ord + E
}

computePsi <- function(X_psi, beta_psi, U, LL){

  logit_psi = X_psi %*% beta_psi + U %*% LL

  logistic(logit_psi)

}

computeTheta <- function(X_theta, beta_theta){
  logistic(X_theta %*% beta_theta)
}

