# sampleresults fixture: 1000 draws, 10 species, 100 sites, 3 primers, d=2,
# ncov_psi=2, ncov_theta=2, ncov_ord=2.
# Fixtures: loaded by helper-fixtures.R

# ---------------------------------------------------------------------------
# returnOccupancyCovariates()
