sample_E <- function(k, Omega, X_psi, beta_psi, X_ord, beta_ord, LL){

  d <- nrow(LL)
  n <- nrow(k)

  k_new <- k - Omega * (X_psi %*% beta_psi + X_ord %*% beta_ord %*% LL)

