        ) + dbinom(0, 1, psi[i,s], log = T)

      p_1 <- exp(p_zsequal1) / (exp(p_zsequal1) + exp(p_zsequal0))

      z[i,s] <- rbinom(1, 1, p_1)

    }

  }

  z
}

